const data = $input.item.json;
const hourly = data.hourly;
const len = hourly.time.length;

function getStats(arr) {
  const valid = arr.filter(v => v !== null);
  const mean = valid.reduce((a,b)=>a+b,0)/valid.length;
  const std = Math.sqrt(valid.reduce((a,b)=>a+Math.pow(b-mean,2),0)/valid.length);
  return {mean, std};
}

const stats = {
  temp: getStats(hourly.temperature_2m),
  precip: getStats(hourly.precipitation),
  wind: getStats(hourly.windspeed_10m),
  humidity: getStats(hourly.relativehumidity_2m),
  pressure: getStats(hourly.surface_pressure)
};

let anomalies = [];
let maxDeviation = 0;
let primaryDriver = '';

for(let i=0; i<len; i++) {
  let isAnomaly = false;
  let deviations = {};

  const checkVar = (val, stat, name) => {
    if (val === null) return 0;
    const dev = Math.abs(val - stat.mean) / (stat.std || 1);
    deviations[name] = dev;
    if (dev > 2.5) {
      isAnomaly = true;
      if (dev > maxDeviation) {
        maxDeviation = dev;
        primaryDriver = name;
      }
    }
    return dev;
  };

  checkVar(hourly.temperature_2m[i], stats.temp, 'temperature');
  checkVar(hourly.precipitation[i], stats.precip, 'precipitation');
  checkVar(hourly.windspeed_10m[i], stats.wind, 'windspeed');
  checkVar(hourly.relativehumidity_2m[i], stats.humidity, 'humidity');
  checkVar(hourly.surface_pressure[i], stats.pressure, 'pressure');

  if (isAnomaly) {
    anomalies.push({
      time: hourly.time[i],
      temp: hourly.temperature_2m[i],
      precip: hourly.precipitation[i],
      deviations
    });
  }
}

const severity_score = Math.min(100, Math.round(maxDeviation * 15));

return { json: {
  location: data.timezone,
  lat: data.latitude,
  lon: data.longitude,
  severity_score,
  anomaly_count: anomalies.length,
  primary_driver: primaryDriver,
  stats,
  recent_anomalies: anomalies.slice(-5),
  hourly_data: { 
      time: hourly.time.slice(-24), 
      temp: hourly.temperature_2m.slice(-24), 
      precip: hourly.precipitation.slice(-24), 
      humidity: hourly.relativehumidity_2m.slice(-24),
      wind: hourly.windspeed_10m.slice(-24),
      pressure: hourly.surface_pressure.slice(-24)
  }
}};

const geminiRaw = $input.item.json;
const climateData = $('Process Climate Data').item.json;

let geminiParsed = {};
try {
  const text = geminiRaw.candidates[0].content.parts[0].text;
  const jsonStr = text.replace(/```json\n?|```/g, '').trim();
  geminiParsed = JSON.parse(jsonStr);
} catch(e) {
  geminiParsed = {
    narrative: "Failed to parse AI response.",
    risk_level: "Unknown",
    primary_driver: climateData.primary_driver,
    recommendation: "Monitor closely.",
    confidence: 0,
    forecast_warning: "Data unavailable."
  };
}

return { json: { ...climateData, ai_analysis: geminiParsed } };
